/**
 * Position an existing generation that has NULL timeline_frame.
 */
export const usePositionExistingGenerationInShot = () => {
  const queryClient = useQueryClient();

  return useMutation({
    mutationFn: async ({
      shot_id,
      generation_id,
      project_id,
    }: {
      shot_id: string;
      generation_id: string;
      project_id: string;
    }) => {
      const { data, error } = await supabase().rpc('add_generation_to_shot', {
        p_shot_id: shot_id,
        p_generation_id: generation_id,
        p_with_position: true,
      });

      if (error) {
        throw error;
      }

      return { shot_id, generation_id, project_id, data };
    },

    onSuccess: (data) => {
      enqueueGenerationsInvalidation(queryClient, data.shot_id, {
        reason: 'add-image-to-shot',
        scope: 'all',
        includeShots: true,
        projectId: data.project_id,
        includeProjectUnified: true,
      });
    },

    onError: (error: Error) => {
      toast.error(`Failed to position image: ${error.message}`);
    },
  });
};

import { beforeEach, describe, expect, it, vi } from 'vitest';

const mocks = vi.hoisted(() => ({
  applyAtomicShotCacheUpdate: vi.fn(),
}));

vi.mock('./shotCacheUpdate', () => ({
  applyAtomicShotCacheUpdate: (...args: unknown[]) => mocks.applyAtomicShotCacheUpdate(...args),
}));

import {
  createEmptyShotPath,
  createShotWithFilesPath,
  createShotWithGenerationPath,
} from './shotCreationPaths';

describe('shotCreationPaths', () => {
  beforeEach(() => {
    vi.clearAllMocks();
  });

  it('creates a shot from an existing generation and updates the optimistic cache', async () => {
    const createShotWithImage = vi.fn().mockResolvedValue({
      shotId: 'shot-1',
      shotName: 'Shot 1',
      shotGenerationId: 'shot-gen-1',
    });

    const result = await createShotWithGenerationPath({
      selectedProjectId: 'project-1',
      shotName: 'Seed Shot',
      generationId: 'generation-1',
      generationPreview: { imageUrl: 'preview.png' },
      shots: [{ id: 'shot-0' }] as never,
      queryClient: { id: 'query-client' } as never,
      createShotWithImage,
    });

    expect(createShotWithImage).toHaveBeenCalledWith({
      projectId: 'project-1',
      shotName: 'Seed Shot',
      generationId: 'generation-1',
    });
    expect(mocks.applyAtomicShotCacheUpdate).toHaveBeenCalledWith(
      expect.objectContaining({
        selectedProjectId: 'project-1',
        shotId: 'shot-1',
        shotName: 'Shot 1',
        shotGenerationId: 'shot-gen-1',
        generationId: 'generation-1',
      }),
    );
    expect(result).toEqual({
      shotId: 'shot-1',
      shotName: 'Shot 1',
      generationIds: ['generation-1'],
