/**
 * Shot-scoped image queries. Queries shot_generations JOIN generations.
 * Exports: useShotImages, useTimelineImages, useUnpositionedImages, useVideoOutputs.
 */

import { useQuery, useQueryClient, UseQueryResult } from '@tanstack/react-query';
import { getSupabaseClient as supabase } from '@/integrations/supabase/client';
import { GenerationRow } from '@/domains/generation/types';
import { QUERY_PRESETS, STANDARD_RETRY, STANDARD_RETRY_DELAY } from '@/shared/lib/query/queryDefaults';
import { generationQueryKeys } from '@/shared/lib/queryKeys/generations';
import { normalizeAndPresentError } from '@/shared/lib/errorHandling/runtimeError';
import React from 'react';

import { mapShotGenerationToRow } from '@/shared/hooks/shots';
import {
  selectTimelineImages,
  selectUnpositionedImages,
  selectVideoOutputs,
} from '@/shared/lib/shotImageSelectors';

/** Loads all shot_generations (positioned + unpositioned) for a shot. */
const useAllShotGenerations = (
  shotId: string | null,
  options?: {
    // When true, prevents query from refetching during sensitive operations (drag, persist, etc.)
    disableRefetch?: boolean;
  }
): UseQueryResult<GenerationRow[]> => {
  const stableShotId = React.useMemo(() => shotId, [shotId]);
  const isEnabled = React.useMemo(() => {
    if (options?.disableRefetch) {
      return false;
    }
    return !!stableShotId;
  }, [stableShotId, options?.disableRefetch]);

  const queryClient = useQueryClient();

  const mainQuery = useQuery<GenerationRow[], Error>({
    queryKey: generationQueryKeys.byShot(stableShotId!),
    enabled: isEnabled,
    // Use realtimeBacked preset - data freshness from realtime + mutations
    // (invalidated by RealtimeProvider + useGenerationInvalidation)
    ...QUERY_PRESETS.realtimeBacked,
    // realtimeBacked provides staleTime: 30_000 — don't override to 0.
    // staleTime: 0 makes the query perpetually stale, which combined with React Query's
    // observer.setOptions() running every render causes a fetch→render→fetch loop.
    // refetchOnMount: 'always' ensures fresh data when opening a shot without the loop.
    refetchOnMount: 'always',
    retry: STANDARD_RETRY,
    // NOTE: Removed placeholderData: (previousData) => previousData
    // This was causing cross-shot data leakage - when navigating to a new shot,
    // the previous shot's images would briefly appear as "placeholder" data
    queryFn: async ({ signal }) => {
      // Query shot_generations with embedded generations data + primary variant
      // NOTE: Must specify FK explicitly to avoid ambiguous relationship error (PGRST201)
      // since there are two FKs between shot_generations and generations
      // We also fetch the primary_variant using the generations.primary_variant_id FK
      // to get the correct display URL (primary variant may differ from generation.location)
      const response = await supabase().from('shot_generations')
        .select(`
          id,
          generation_id,
          timeline_frame,
          metadata,
          generation:generations!shot_generations_generation_id_generations_id_fk (
            id,
            location,
            thumbnail_url,
            type,
            created_at,
            starred,
            name,
            based_on,
            params,
            primary_variant_id,
            primary_variant:generation_variants!generations_primary_variant_id_fkey (
              location,
              thumbnail_url
            )
          )
        `)
        .eq('shot_id', stableShotId!)
        .order('timeline_frame', { ascending: true, nullsFirst: false })
        .abortSignal(signal);

      if (response.error) {
        // Abort errors are expected during rapid invalidations - silently return cached data
        if (response.error.code === '20' || response.error.message?.includes('abort')) {
          const cachedData = queryClient.getQueryData<GenerationRow[]>(generationQueryKeys.byShot(stableShotId!));
          return cachedData || [];
        }
        normalizeAndPresentError(response.error, {
          context: 'useShotImages.queryFn',
          showToast: false,
          logData: { shotId: stableShotId },
        });
        throw response.error;
      }

      return (response.data || [])
        .map(mapShotGenerationToRow)
        .filter(Boolean) as GenerationRow[];
    },
    retryDelay: STANDARD_RETRY_DELAY,
  });

  return mainQuery as UseQueryResult<GenerationRow[]>;
};

/** Positioned, non-video images with valid location, sorted by timeline_frame. */
export const useTimelineImages = (
  shotId: string | null
): UseQueryResult<GenerationRow[]> => {
  const baseQuery = useAllShotGenerations(shotId);

  const filtered = React.useMemo(() => {
    if (!baseQuery.data) return undefined;

    return selectTimelineImages(baseQuery.data);
  }, [baseQuery.data]);

  return { ...baseQuery, data: filtered } as UseQueryResult<GenerationRow[]>;
};

/** Non-video images with no timeline_frame. */
export const useUnpositionedImages = (
  shotId: string | null
): UseQueryResult<GenerationRow[]> => {
  const baseQuery = useAllShotGenerations(shotId);

  const filtered = React.useMemo(() => {
    if (!baseQuery.data) return undefined;

    return selectUnpositionedImages(baseQuery.data);
  }, [baseQuery.data]);

  return { ...baseQuery, data: filtered } as UseQueryResult<GenerationRow[]>;
};

/** Video generations in the shot. */
export const useVideoOutputs = (
  shotId: string | null
): UseQueryResult<GenerationRow[]> => {
  const baseQuery = useAllShotGenerations(shotId);

  const filtered = React.useMemo(() => {
    if (!baseQuery.data) return undefined;

    return selectVideoOutputs(baseQuery.data);
  }, [baseQuery.data]);

  return { ...baseQuery, data: filtered } as UseQueryResult<GenerationRow[]>;
};

/** Seeds the shot-generations cache from ShotsContext for instant display on shot select. */
const usePrimeShotGenerationsCache = (
  shotId: string | null,
  contextImages: GenerationRow[] | undefined
) => {
  const queryClient = useQueryClient();

  React.useEffect(() => {
    if (!shotId || !contextImages || contextImages.length === 0) return;

    const existingData = queryClient.getQueryData<GenerationRow[]>(generationQueryKeys.byShot(shotId));
    if (existingData && existingData.length > 0) return;

    // Prime the cache with context data
    queryClient.setQueryData(generationQueryKeys.byShot(shotId), contextImages);
  }, [shotId, contextImages, queryClient]);
};

export const useShotImages = useAllShotGenerations;
export const usePrimeShotImagesCache = usePrimeShotGenerationsCache;

import { useCallback, useMemo, useRef } from 'react';
import { useNavigate } from 'react-router-dom';
import { useCurrentShot } from '@/shared/contexts/CurrentShotContext';
import { useIsMobile } from '@/shared/hooks/mobile';
import { Shot } from '@/domains/generation/types';
import { TOOL_ROUTES, travelShotUrl } from '@/shared/lib/tooling/toolRoutes';
import { dispatchAppEvent } from '@/shared/lib/typedEvents';

interface ShotNavigationOptions {
  /** Whether to scroll to top after navigation */
  scrollToTop?: boolean;
  /** Whether to close mobile panes after navigation */
  closeMobilePanes?: boolean;
  /** Whether to replace the current history entry instead of pushing */
  replace?: boolean;
  /** Custom scroll behavior */
  scrollBehavior?: 'auto' | 'smooth';
  /** Delay before scrolling (useful for waiting for navigation to complete) */
  scrollDelay?: number;
  /** Whether this shot was just created (show loading instead of "not found" while cache syncs) */
  isNewlyCreated?: boolean;
}

interface ShotNavigationResult {
  /** Navigate to a specific shot */
  navigateToShot: (shot: Shot, options?: ShotNavigationOptions) => void;
  /** Navigate to the shot editor without a specific shot (shows shot list) */
  navigateToShotEditor: (options?: ShotNavigationOptions) => void;
  /** Navigate to the next shot in a list */
  navigateToNextShot: (shots: Shot[], currentShot: Shot, options?: ShotNavigationOptions) => boolean;
  /** Navigate to the previous shot in a list */
  navigateToPreviousShot: (shots: Shot[], currentShot: Shot, options?: ShotNavigationOptions) => boolean;
}

const DEFAULT_OPTIONS: Required<ShotNavigationOptions> = {
  scrollToTop: true,
  closeMobilePanes: true,
  replace: false,
  scrollBehavior: 'smooth',
  scrollDelay: 200,
  isNewlyCreated: false,
};

function performScroll(options: Required<ShotNavigationOptions>) {
  if (options.scrollToTop) {
    const scrollFn = () => {
      requestAnimationFrame(() => {
        window.scrollTo({ top: 0, behavior: options.scrollBehavior });
        dispatchAppEvent('app:scrollToTop', { behavior: options.scrollBehavior });
      });
    };

    if (options.scrollDelay > 0) {
      setTimeout(scrollFn, options.scrollDelay);
    } else {
      scrollFn();
    }
  }
}

function closeMobilePanes(options: Required<ShotNavigationOptions>, isMobile: boolean) {
  if (options.closeMobilePanes && isMobile) {
    dispatchAppEvent('mobilePaneOpen', { side: null });
  }
}

export const useShotNavigation = (): ShotNavigationResult => {
  const navigate = useNavigate();
  const { setCurrentShotId } = useCurrentShot();
  const isMobile = useIsMobile();

  // Refs for all dependencies so callbacks are stable (empty deps).
  // Without this, every consumer gets new function references on every render,
  // breaking React.memo on downstream components and cascading re-renders.
  const navigateRef = useRef(navigate);
  navigateRef.current = navigate;
  const setCurrentShotIdRef = useRef(setCurrentShotId);
  setCurrentShotIdRef.current = setCurrentShotId;
  const isMobileRef = useRef(isMobile);
  isMobileRef.current = isMobile;

  const navigateToShot = useCallback((shot: Shot, options: ShotNavigationOptions = {}) => {
    const opts = { ...DEFAULT_OPTIONS, ...options };

    // NOTE: We intentionally do NOT call setCurrentShotId() here.
    // navigate() and setCurrentShotId() are not batched by React — the context
    // update renders before the router update, creating an intermediate frame
    // where currentShotId is set but location.hash is empty. useUrlSync then
    // clears currentShotId, causing a visible EDITOR → shot-list → EDITOR jolt.
    // Instead, we let the hash drive everything: useSelectedShotResolution
    // resolves shotToEdit from hashShotId + shotFromState, and useUrlSync/
    // useSyncCurrentShotId set currentShotId from the hash after navigation.
    const targetUrl = travelShotUrl(shot.id);
    navigateRef.current(targetUrl, {
      state: {
        fromShotClick: true,
        shotData: shot,
        isNewlyCreated: opts.isNewlyCreated
      },
      replace: opts.replace,
    });

    performScroll(opts);
    closeMobilePanes(opts, isMobileRef.current);
  }, []);

  const navigateToShotEditor = useCallback((options: ShotNavigationOptions = {}) => {
    const opts = { ...DEFAULT_OPTIONS, ...options };

    setCurrentShotIdRef.current(null);

    navigateRef.current(TOOL_ROUTES.TRAVEL_BETWEEN_IMAGES, {
      state: { fromShotClick: false },
      replace: opts.replace,
    });

    performScroll(opts);
    closeMobilePanes(opts, isMobileRef.current);
  }, []);

  const navigateToNextShot = useCallback((shots: Shot[], currentShot: Shot, options: ShotNavigationOptions = {}): boolean => {
    const currentIndex = shots.findIndex(shot => shot.id === currentShot.id);
    if (currentIndex >= 0 && currentIndex < shots.length - 1) {
      const nextShot = shots[currentIndex + 1];
      navigateToShot(nextShot, { ...options, replace: true });
      return true;
    }
    return false;
  }, [navigateToShot]);

  const navigateToPreviousShot = useCallback((shots: Shot[], currentShot: Shot, options: ShotNavigationOptions = {}): boolean => {
    const currentIndex = shots.findIndex(shot => shot.id === currentShot.id);
    if (currentIndex > 0) {
      const previousShot = shots[currentIndex - 1];
      navigateToShot(previousShot, { ...options, replace: true });
      return true;
    }
    return false;
  }, [navigateToShot]);

  return useMemo(() => ({
    navigateToShot,
    navigateToShotEditor,
    navigateToNextShot,
    navigateToPreviousShot,
  }), [navigateToShot, navigateToShotEditor, navigateToNextShot, navigateToPreviousShot]);
};

import { useCallback, useRef, useMemo, useEffect } from 'react';
import { TOOL_IDS } from '@/shared/lib/tooling/toolIds';
import { normalizeAndPresentError } from '@/shared/lib/errorHandling/runtimeError';
import { useAutoSaveSettings } from '@/shared/settings/hooks/useAutoSaveSettings';
import {
  VideoTravelSettings,
  DEFAULT_PHASE_CONFIG,
  createDefaultVideoTravelSettings,
  normalizeVideoTravelSettings,
} from '../../settings';
import { STORAGE_KEYS } from '@/shared/lib/storage/storageKeys';
import { getSupabaseClient as supabase } from '@/integrations/supabase/client';
import { toast } from '@/shared/components/ui/runtime/sonner';
import { DEFAULT_STEERABLE_MOTION_SETTINGS } from '../../components/ShotEditor/state/types';
import { useSessionInheritedDefaults } from './inheritedDefaults';

export interface UseShotSettingsReturn {
  // State
  settings: VideoTravelSettings;
  status: 'idle' | 'loading' | 'ready' | 'saving' | 'error';
  /** The shot ID these settings are confirmed for (null if not yet loaded) */
  shotId: string | null;
  isDirty: boolean;
  error: Error | null;

  // Field Updates
  updateField: <K extends keyof VideoTravelSettings>(
    key: K, 
    value: VideoTravelSettings[K]
  ) => void;

  updateFields: (updates: Partial<VideoTravelSettings>) => void;

  // Operations
  applyShotSettings: (sourceShotId: string) => Promise<void>;
  applyProjectDefaults: () => Promise<void>;
  resetToDefaults: () => void;

  // Saving
  save: () => Promise<void>;
  saveImmediate: () => Promise<void>;
  revert: () => void;
}

/**
 * Shot-specific settings hook built on useAutoSaveSettings.
 * 
 * Adds shot-specific functionality:
 * - Session storage inheritance for new shots
 * - localStorage persistence for cross-shot inheritance
 * - Apply settings from another shot
 * - Apply project defaults
 * - Special handling for advancedMode/phaseConfig initialization
 */
export const useShotSettings = (
  shotId: string | null | undefined,
  projectId: string | null | undefined
): UseShotSettingsReturn => {
  const inheritedSettings = useSessionInheritedDefaults<VideoTravelSettings>({
    shotId,
    storageKeyForShot: STORAGE_KEYS.APPLY_PROJECT_DEFAULTS,
    mergeDefaults: (defaults) => {
      const { _uiSettings, ...validSettings } = defaults;
      return normalizeVideoTravelSettings({
        ...createDefaultVideoTravelSettings(),
        ...validSettings,
        steerableMotionSettings: {
          ...DEFAULT_STEERABLE_MOTION_SETTINGS,
          ...(typeof validSettings.steerableMotionSettings === 'object' && validSettings.steerableMotionSettings
            ? validSettings.steerableMotionSettings
            : {}),
        },
      });
    },
    context: 'useShotSettings',
  });

  // Use the shared auto-save hook with inherited settings as initial defaults
  const autoSave = useAutoSaveSettings<VideoTravelSettings>({
    toolId: TOOL_IDS.TRAVEL_BETWEEN_IMAGES,
    shotId,
    projectId,
    scope: 'shot',
    defaults: inheritedSettings || createDefaultVideoTravelSettings(),
    enabled: !!shotId,
    debounceMs: 300,
  });
  const {
    settings,
    status,
    entityId,
    isDirty,
    error,
    hasShotSettings,
    updateField: autoSaveUpdateField,
    updateFields: autoSaveUpdateFields,
    saveImmediate,
    revert,
  } = autoSave;

  // Save inherited settings to DB immediately if we have them
  // CRITICAL: Only save if the shot doesn't already have settings in DB
  // to prevent overwriting existing settings with inherited defaults
  // We use `hasShotSettings` from useToolSettings which checks at the DB level
  useEffect(() => {
    // Only save inherited settings if:
    // 1. We have inherited settings
    // 2. Status is ready
    // 3. DB did NOT have existing settings (hasShotSettings is false)
    if (inheritedSettings && shotId && status === 'ready') {
      if (!hasShotSettings) {
        // Persist inherited settings immediately via the canonical auto-save boundary.
        saveImmediate(inheritedSettings).catch(err => {
          normalizeAndPresentError(err, { context: 'useShotSettings', showToast: false });
        });
      }
    }
  }, [inheritedSettings, shotId, status, hasShotSettings, saveImmediate]);

  // Persist settings to localStorage for future inheritance
  useEffect(() => {
    if (shotId && projectId && status === 'ready' && settings) {
      try {
        // Project-specific key
        const projectStorageKey = STORAGE_KEYS.LAST_ACTIVE_SHOT_SETTINGS(projectId);
        localStorage.setItem(projectStorageKey, JSON.stringify(settings));

        // Global key (without pairConfigs which are shot-specific)
        const globalSettings = { ...settings, pairConfigs: [] };
        localStorage.setItem(STORAGE_KEYS.GLOBAL_LAST_ACTIVE_SHOT_SETTINGS, JSON.stringify(globalSettings));
      } catch (e) {
        normalizeAndPresentError(e, { context: 'useShotSettings', showToast: false });
      }
    }
  }, [settings, shotId, projectId, status]);

  // Refs for callbacks that need latest values without recreation
  const autoSaveSettingsRef = useRef(autoSave.settings);
  autoSaveSettingsRef.current = autoSave.settings;
  const shotIdRef = useRef(shotId);
  shotIdRef.current = shotId;
  const projectIdRef = useRef(projectId);
  projectIdRef.current = projectId;

  // Wrapped updateField with special handling for advancedMode/phaseConfig
  const updateField = useCallback(<K extends keyof VideoTravelSettings>(
    key: K,
    value: VideoTravelSettings[K]
  ) => {
    // Handle special case: when switching to advanced mode, initialize phaseConfig
    if (key === 'advancedMode' && value === true) {
      const currentSettings = autoSaveSettingsRef.current;
      if (!currentSettings.phaseConfig) {
        autoSaveUpdateFields({
          [key]: value,
          phaseConfig: DEFAULT_PHASE_CONFIG,
        } as Partial<VideoTravelSettings>);
        return;
      }
    }
    if (key === 'motionMode' && value === 'advanced') {
      const currentSettings = autoSaveSettingsRef.current;
      if (!currentSettings.phaseConfig) {
        autoSaveUpdateFields({
          [key]: value,
          phaseConfig: DEFAULT_PHASE_CONFIG,
        } as Partial<VideoTravelSettings>);
        return;
      }
    }

    autoSaveUpdateField(key, value);
  }, [autoSaveUpdateField, autoSaveUpdateFields]);

  // Apply settings from another shot
  const applyShotSettings = useCallback(async (sourceShotId: string) => {
    if (!shotIdRef.current || !sourceShotId) {
      toast.error('Cannot apply settings: missing shot ID');
      return;
    }

    try {
      const { data, error: fetchError } = await supabase().from('shots')
        .select('settings')
        .eq('id', sourceShotId)
        .single();

      if (fetchError) throw fetchError;

      const sourceSettingsRaw = (data?.settings as Record<string, unknown>)?.[TOOL_IDS.TRAVEL_BETWEEN_IMAGES];

      if (sourceSettingsRaw) {
        autoSaveUpdateFields(normalizeVideoTravelSettings(sourceSettingsRaw));
      } else {
        toast.error('Source shot has no settings');
      }
    } catch (err) {
      normalizeAndPresentError(err, { context: 'useShotSettings', toastTitle: 'Failed to apply settings' });
    }
  }, [autoSaveUpdateFields]);

  // Apply project defaults
  const applyProjectDefaults = useCallback(async () => {
    if (!projectIdRef.current) {
      toast.error('Cannot apply defaults: no project selected');
      return;
    }

    try {
      const { data, error: fetchError } = await supabase().from('projects')
        .select('settings')
        .eq('id', projectIdRef.current)
        .single();

      if (fetchError) throw fetchError;

      const projectDefaultsRaw = (data?.settings as Record<string, unknown>)?.[TOOL_IDS.TRAVEL_BETWEEN_IMAGES];

      if (projectDefaultsRaw) {
        autoSaveUpdateFields(normalizeVideoTravelSettings(projectDefaultsRaw));
      } else {
        toast.error('Project has no default settings');
      }
    } catch (err) {
      normalizeAndPresentError(err, { context: 'useShotSettings', toastTitle: 'Failed to apply defaults' });
    }
  }, [autoSaveUpdateFields]);

  // Reset to hardcoded defaults
  const resetToDefaults = useCallback(() => {
    autoSaveUpdateFields(createDefaultVideoTravelSettings());
  }, [autoSaveUpdateFields]);

  // Memoize return value
  return useMemo(() => ({
    settings,
    status: status as 'idle' | 'loading' | 'ready' | 'saving' | 'error',
    shotId: entityId,
    isDirty,
    error,
    updateField,
    updateFields: autoSaveUpdateFields,
    applyShotSettings,
    applyProjectDefaults,
    resetToDefaults,
    save: saveImmediate,
    saveImmediate,
    revert,
  }), [
    settings,
    status,
    entityId,
    isDirty,
    error,
    updateField,
    autoSaveUpdateFields,
    saveImmediate,
    revert,
    applyShotSettings,
    applyProjectDefaults,

