 48	export function SelectionContextMenu({
 49	  position,
 50	  onClose,
 51	  onCreateShot,
 52	  onGenerateVideo,
 53	  isCreating = false,
 54	}: SelectionContextMenuProps) {
 55	  const menuRef = useRef<HTMLDivElement>(null);
 56	
 57	  useEffect(() => {
 58	    if (!position) {
 59	      return undefined;
 60	    }
 61	
 62	    const handleClickAway = (event: MouseEvent) => {
 63	      if (menuRef.current && !menuRef.current.contains(event.target as Node)) {
 64	        onClose();
 65	      }
 66	    };
 67	    const handleEscape = (event: KeyboardEvent) => {
 68	      if (event.key === 'Escape') {
 69	        onClose();
 70	      }
 71	    };
 72	
 73	    document.addEventListener('mousedown', handleClickAway);
 74	    document.addEventListener('keydown', handleEscape);
 75	    return () => {
 76	      document.removeEventListener('mousedown', handleClickAway);
 77	      document.removeEventListener('keydown', handleEscape);
 78	    };
 79	  }, [position, onClose]);
 80	
 81	  if (!position) {
 82	    return null;
 83	  }
 84	
 85	  const handleAction = (action: () => void | Promise<void>) => {
 86	    onClose();
 87	    void action();
 88	  };
 89	
 90	  return createPortal(
 91	    <div
 92	      ref={menuRef}
 93	      className="fixed z-50 min-w-[12rem] overflow-hidden rounded-md border bg-popover p-1 text-popover-foreground shadow-md animate-in fade-in-0 zoom-in-95"
