import React from 'react';
import { MediaGallery, type GalleryFilterState } from '@/shared/components/MediaGallery';
import { useGallerySelection } from '@/shared/contexts/GallerySelectionContext';
import { SkeletonGallery } from '@/shared/components/ui/composed/skeleton-gallery';
import { useLassoSelection } from '../hooks/useLassoSelection';
import { useModifierKeys } from '../hooks/useModifierKeys';

type MediaGalleryProps = React.ComponentProps<typeof MediaGallery>;

interface GenerationsPaneLayoutModel {
  columns: number;
  itemsPerPage: number;
}

interface GenerationsPaneLoadingModel {
  isLoading: boolean;
  expectedItemCount?: number;
}

interface GenerationsPanePageModel {
  page: number;
  totalCount: number;
}

interface GenerationsPaneGalleryModel {
  items: MediaGalleryProps['images'];
  onDelete: NonNullable<MediaGalleryProps['onDelete']>;
  onToggleStar: NonNullable<MediaGalleryProps['onToggleStar']>;
  isDeleting: boolean;
  allShots: NonNullable<MediaGalleryProps['allShots']>;
  lastShotId?: string;
  filters: GalleryFilterState;
  onFiltersChange: (newFilters: GalleryFilterState) => void;
  onAddToShot: NonNullable<MediaGalleryProps['onAddToLastShot']>;
  onAddToShotWithoutPosition: NonNullable<MediaGalleryProps['onAddToLastShotWithoutPosition']>;
  onServerPageChange: NonNullable<
    NonNullable<MediaGalleryProps['pagination']>['onServerPageChange']
  >;
  generationFilters: MediaGalleryProps['generationFilters'];
  currentViewingShotId?: string;
  onCreateShot: NonNullable<MediaGalleryProps['onCreateShot']>;
}

interface GenerationsPaneGalleryProps {
  containerRef: React.RefObject<HTMLDivElement | null>;
  projectAspectRatio?: string;
  layout: GenerationsPaneLayoutModel;
  loading: GenerationsPaneLoadingModel;
  pagination: GenerationsPanePageModel;
  error: Error | null;
  gallery: GenerationsPaneGalleryModel;
}

export function GenerationsPaneGallery({
  containerRef,
  projectAspectRatio,
  layout,
  loading,
  pagination,
  error,
  gallery,
}: GenerationsPaneGalleryProps): React.ReactElement {
  const gallerySurfaceRef = React.useRef<HTMLDivElement | null>(null);
  const { selectedGalleryIds, selectGalleryItem, selectGalleryItems } = useGallerySelection();
  const modifierKeys = useModifierKeys();
  const { selectionRect, handleMouseDown } = useLassoSelection({
    containerRef: gallerySurfaceRef,
    items: gallery.items,
    onSelectItems: selectGalleryItems,
  });

  const handleImageClick = React.useCallback((image: MediaGalleryProps['images'][number]) => {
    selectGalleryItem(
      image.id,
      {
        url: image.url,
        type: image.type ?? image.contentType ?? (image.isVideo ? 'video/mp4' : 'image/png'),
        generationId: image.generation_id ?? image.id,
      },
      { toggle: modifierKeys.isMultiSelectModifier },
    );
  }, [modifierKeys.isMultiSelectModifier, selectGalleryItem]);

  return (
    <div
      ref={containerRef}
      className="flex-grow px-1 sm:px-3 overflow-y-auto overscroll-contain flex flex-col"
      style={{ WebkitOverflowScrolling: 'touch' }}
      data-tour="gallery-section"
    >
      {loading.isLoading && gallery.items.length === 0 && (
        <SkeletonGallery
          count={loading.expectedItemCount ?? layout.itemsPerPage}
          fixedColumns={layout.columns}
          gapClasses="gap-2 sm:gap-4"
          darkSurface
          showControls={false}
          projectAspectRatio={projectAspectRatio}
          className="space-y-0 pb-4 pt-2"
        />
      )}

      {error && <p className="text-red-500 text-center">Error: {error.message}</p>}

      {gallery.items.length > 0 && (
        <div className={loading.isLoading ? 'opacity-60 pointer-events-none transition-opacity duration-200' : ''}>
          <div
            ref={gallerySurfaceRef}
            className="relative"
            onMouseDown={handleMouseDown}
          >
            <MediaGallery
              images={gallery.items}
              onDelete={gallery.onDelete}
              onToggleStar={gallery.onToggleStar}
              isDeleting={gallery.isDeleting}
              allShots={gallery.allShots}
              lastShotId={gallery.lastShotId}
              filters={gallery.filters}
              onFiltersChange={gallery.onFiltersChange}
              columnsPerRow={layout.columns}
              onImageClick={handleImageClick}
              onAddToLastShot={(targetShotId, generationId, imageUrl, thumbUrl) => {
                return gallery.onAddToShot(targetShotId, generationId, imageUrl, thumbUrl);
              }}
              onAddToLastShotWithoutPosition={(targetShotId, generationId, imageUrl, thumbUrl) => {
                return gallery.onAddToShotWithoutPosition(targetShotId, generationId, imageUrl, thumbUrl);
              }}
              className="space-y-0 pb-8"
              selectedIds={selectedGalleryIds}
              config={{
                darkSurface: true,
                reducedSpacing: true,
                hidePagination: true,
                hideTopFilters: true,
                showShare: false,
                enableSingleClick: true,
              }}
              pagination={{
                offset: (pagination.page - 1) * layout.itemsPerPage,
                totalCount: pagination.totalCount,
                itemsPerPage: layout.itemsPerPage,
                serverPage: pagination.page,
                onServerPageChange: gallery.onServerPageChange,
              }}
              generationFilters={gallery.generationFilters}
              currentViewingShotId={gallery.currentViewingShotId}
              onCreateShot={gallery.onCreateShot}
            />
            {selectionRect && (
              <div
                className="pointer-events-none absolute border border-sky-400 bg-sky-400/10"
                style={{
                  left: selectionRect.left,
                  top: selectionRect.top,
                  width: selectionRect.width,
                  height: selectionRect.height,
                }}
              />
            )}
          </div>
        </div>
      )}

      {gallery.items.length === 0 && !loading.isLoading && (
        <div className="flex-1 flex items-center justify-center text-zinc-500">
          No generations found for this project.
        </div>
      )}
    </div>
  );
}

import React, { useCallback, useEffect, useRef, useState } from 'react';
import { createPortal } from 'react-dom';
import { ImageIcon, Layers, Music2, RefreshCw, Scissors, Trash2, Type, X } from 'lucide-react';
import { cn } from '@/shared/components/ui/contracts/cn';
import type { ClipMeta } from '@/tools/video-editor/lib/timeline-data';
import type { TimelineAction } from '@/tools/video-editor/types/timeline-canvas';

interface ContextMenuState {
  x: number;
  y: number;
  clientX: number;
}

interface ClipActionProps {
  action: TimelineAction;
  clipMeta: ClipMeta;
  isSelected: boolean;
  isPrimary?: boolean;
  selectedClipIds?: string[];
  thumbnailSrc?: string;
  onSelect: (clipId: string, trackId: string) => void;
  onDoubleClickAsset?: (assetKey: string) => void;
  onSplitHere?: (clipId: string, clientX: number) => void;
  onSplitClipsAtPlayhead?: (clipIds: string[]) => void;
  onDeleteClip?: (clipId: string) => void;
  onDeleteClips?: (clipIds: string[]) => void;
  onToggleMuteClips?: (clipIds: string[]) => void;
  /** True when the clip's file no longer matches the generation's current primary variant */
  isVariantStale?: boolean;
  /** True when the clip is linked to a generation (enables "Update to current variant" in menu) */
  isGenerationAsset?: boolean;
  onUpdateVariant?: () => void;
  onDismissStale?: () => void;
}

export function ClipAction({
  action,
  clipMeta,
  isSelected,
  isPrimary = false,
  selectedClipIds = [],
  thumbnailSrc,
  onSelect,
  onDoubleClickAsset,
  onSplitHere,
  onSplitClipsAtPlayhead,
  onDeleteClip,
  onDeleteClips,
  onToggleMuteClips,
  isVariantStale,
  isGenerationAsset,
  onUpdateVariant,
  onDismissStale,
}: ClipActionProps) {
  const [contextMenu, setContextMenu] = useState<ContextMenuState | null>(null);
  const menuRef = useRef<HTMLDivElement>(null);

  const closeMenu = useCallback(() => setContextMenu(null), []);

  useEffect(() => {
    if (!contextMenu) return;
    const handleClickOutside = (e: MouseEvent) => {
      if (menuRef.current && !menuRef.current.contains(e.target as Node)) {
        closeMenu();
      }
    };
    const handleEscape = (e: KeyboardEvent) => {
      if (e.key === 'Escape') closeMenu();
    };
    document.addEventListener('mousedown', handleClickOutside);
    document.addEventListener('keydown', handleEscape);
    return () => {
      document.removeEventListener('mousedown', handleClickOutside);
      document.removeEventListener('keydown', handleEscape);
    };
  }, [contextMenu, closeMenu]);

  const handleContextMenu = useCallback((e: React.MouseEvent) => {
    e.preventDefault();
    e.stopPropagation();
    if (!isSelected) {
      onSelect(action.id, clipMeta.track);
    }
    setContextMenu({ x: e.clientX, y: e.clientY, clientX: e.clientX });
  }, [action.id, clipMeta.track, isSelected, onSelect]);
  const isEffectLayer = clipMeta.clipType === 'effect-layer';
  const icon = isEffectLayer
    ? <Layers className="h-3 w-3" />
    : clipMeta.clipType === 'text'
    ? <Type className="h-3 w-3" />
    : clipMeta.track.startsWith('A')
      ? <Music2 className="h-3 w-3" />
      : <ImageIcon className="h-3 w-3" />;
  const hasBatchSelection = isSelected && selectedClipIds.length > 1;
  const effectBadges = [
    clipMeta.entrance?.type ? `In:${clipMeta.entrance.type}` : null,
    clipMeta.continuous?.type ? `Loop:${clipMeta.continuous.type}` : null,
    clipMeta.exit?.type ? `Out:${clipMeta.exit.type}` : null,
  ].filter(Boolean);

  return (
    <>
      <button
        type="button"
        className={cn(
          'clip-action group relative flex h-full w-full overflow-hidden rounded-md border text-left',
          isEffectLayer && isSelected
            ? 'border-violet-400 bg-violet-500/20 text-violet-50'
            : isEffectLayer
              ? 'border-violet-500/30 bg-violet-500/10 text-violet-300 hover:border-violet-400/60'
            : isSelected
            ? 'border-sky-400 bg-sky-500/20 text-sky-50'
            : 'border-border bg-card/90 text-foreground hover:border-accent',
        )}
        data-clip-id={action.id}
        data-row-id={clipMeta.track}
        onPointerDown={(event) => event.stopPropagation()}
        onDoubleClick={(event) => {
          event.stopPropagation();
          if (!isEffectLayer && clipMeta.clipType !== 'text' && clipMeta.asset) {
            onDoubleClickAsset?.(clipMeta.asset);
          }
        }}
        onContextMenu={handleContextMenu}
      >
        {thumbnailSrc ? (
          <img
            src={thumbnailSrc}
            alt=""
            className="h-full w-10 shrink-0 object-cover opacity-80"
            draggable={false}
          />
        ) : (
          <div className="flex h-full w-8 shrink-0 items-center justify-center bg-background/60 text-muted-foreground">
            {icon}
          </div>
        )}
        <div className="min-w-0 flex-1 px-2 py-1">
          <div className="truncate text-[11px] font-medium">
            {isEffectLayer
              ? (clipMeta.continuous?.type || 'Effect Layer')
              : (clipMeta.text?.content || clipMeta.asset || action.id)}
          </div>
          {effectBadges.length > 0 && (
            <div className="mt-1 flex gap-1 overflow-hidden">
              {effectBadges.slice(0, 2).map((badge) => (
                <span key={badge} className="truncate rounded bg-background/60 px-1 py-0.5 text-[9px] uppercase tracking-[0.12em] text-muted-foreground">
                  {badge}
                </span>
              ))}
            </div>
          )}
        </div>
        {isVariantStale && (
          <div
            className="absolute right-1 top-1 flex h-4 w-4 cursor-pointer items-center justify-center rounded-full bg-amber-500 text-white hover:bg-amber-400"
            title="Variant outdated"
            role="button"
            onClick={(e) => {
              e.stopPropagation();
              if (!isSelected) {
                onSelect(action.id, clipMeta.track);
              }
              setContextMenu({ x: e.clientX, y: e.clientY, clientX: e.clientX });
            }}
          >
            <RefreshCw className="h-2.5 w-2.5" />
          </div>
        )}
      </button>

      {contextMenu && createPortal(
        <div
          ref={menuRef}
          className="fixed z-50 min-w-[10rem] overflow-hidden rounded-md border bg-popover p-1 text-popover-foreground shadow-md animate-in fade-in-0 zoom-in-95"
          style={{ left: contextMenu.x, top: contextMenu.y }}
        >
          {!hasBatchSelection && isGenerationAsset && onUpdateVariant && (
            <button
              type="button"
              className="relative flex w-full cursor-default select-none items-center gap-2 rounded-sm px-2 py-1.5 text-sm outline-none transition-colors hover:bg-accent hover:text-accent-foreground"
              onClick={() => {
                onUpdateVariant();
                closeMenu();
              }}
            >
              <RefreshCw className="h-4 w-4" />
              Update to current variant
            </button>
          )}
          {!hasBatchSelection && isVariantStale && onDismissStale && (
            <button
              type="button"
              className="relative flex w-full cursor-default select-none items-center gap-2 rounded-sm px-2 py-1.5 text-sm outline-none transition-colors hover:bg-accent hover:text-accent-foreground"
              onClick={() => {
                onDismissStale();
                closeMenu();
              }}
            >
              <X className="h-4 w-4" />
              Dismiss reminder
            </button>
          )}
          {((isGenerationAsset && onUpdateVariant) || (isVariantStale && onDismissStale)) && !hasBatchSelection && (
            <div className="my-1 h-px bg-border" />
          )}
          {!hasBatchSelection && onSplitHere && (
            <button
              type="button"
              className="relative flex w-full cursor-default select-none items-center gap-2 rounded-sm px-2 py-1.5 text-sm outline-none transition-colors hover:bg-accent hover:text-accent-foreground"
              onClick={() => {
                onSplitHere(action.id, contextMenu.clientX);
                closeMenu();
              }}
            >
              <Scissors className="h-4 w-4" />
              Split Here
            </button>
          )}
          {hasBatchSelection && onToggleMuteClips && (
            <button
              type="button"
              className="relative flex w-full cursor-default select-none items-center gap-2 rounded-sm px-2 py-1.5 text-sm outline-none transition-colors hover:bg-accent hover:text-accent-foreground"
              onClick={() => {
                onToggleMuteClips(selectedClipIds);
                closeMenu();
              }}
            >
              <Music2 className="h-4 w-4" />
              Mute/Unmute {selectedClipIds.length} clips
            </button>
          )}
          {hasBatchSelection && onSplitClipsAtPlayhead && (
            <button
              type="button"
              className="relative flex w-full cursor-default select-none items-center gap-2 rounded-sm px-2 py-1.5 text-sm outline-none transition-colors hover:bg-accent hover:text-accent-foreground"
              onClick={() => {
                onSplitClipsAtPlayhead(selectedClipIds);
                closeMenu();
              }}
            >
              <Scissors className="h-4 w-4" />
              Split {selectedClipIds.length} clips at playhead
            </button>
          )}
          {hasBatchSelection && onDeleteClips ? (
            <button
              type="button"
              className="relative flex w-full cursor-default select-none items-center gap-2 rounded-sm px-2 py-1.5 text-sm outline-none transition-colors hover:bg-destructive hover:text-destructive-foreground"
              onClick={() => {
                onDeleteClips(selectedClipIds);
                closeMenu();
              }}
            >
