  it('toggles selection on modifier-assisted click and renders lasso overlay', () => {
    const selectGalleryItem = vi.fn();
    mocks.useGallerySelection.mockReturnValue({
      selectedGalleryIds: new Set(['g1']),
      selectGalleryItem,
      selectGalleryItems: vi.fn(),
