function resolveLightboxDeletingId(
  isDeleting: string | boolean | null | undefined,
  activeMediaId: string | undefined,
): string | null {
  if (typeof isDeleting === 'string') {
    return isDeleting;
  }
  if (isDeleting && activeMediaId) {
    return activeMediaId;
  }
  return null;
}

