 27	export function resolveSelectedGenerationIdsForShotCreation({
 28	  rows,
 29	  meta,
 30	  registry,
 31	  selectedClipIds,
 32	}: {
 33	  rows: TimelineRow[];
 34	  meta: Record<string, ClipMeta>;
 35	  registry: AssetRegistry;
 36	  selectedClipIds: Iterable<string>;
 37	}) {
 38	  const selectedSet = new Set(selectedClipIds);
 39	  if (selectedSet.size === 0) {
 40	    return { canCreateShot: false, generationIds: [] as string[] };
 41	  }
 42	
 43	  const orderedSelections = rows
 44	    .flatMap((row, trackIndex) => row.actions
 45	      .filter((action) => selectedSet.has(action.id))
 46	      .map((action) => {
 47	        const assetKey = meta[action.id]?.asset;
 48	        const assetEntry = assetKey ? registry.assets[assetKey] : undefined;
 49	
 50	        return {
 51	          trackIndex,
 52	          start: action.start,
 53	          generationId: assetEntry?.generationId,
 54	        };
 55	      }))
 56	    .sort((left, right) => left.trackIndex - right.trackIndex || left.start - right.start);
 57	
 58	  const generationIds = orderedSelections
 59	    .map((selection) => selection.generationId)
 60	    .filter((generationId): generationId is string => typeof generationId === 'string' && generationId.length > 0);
 61	
 62	  return {
 63	    canCreateShot: orderedSelections.length > 0 && generationIds.length === orderedSelections.length,
 64	    generationIds,
 65	  };
 66	}
