import type { ShotCreationResult } from './shotCreationTypes';
import type {
  CreateEmptyShotPathInput,
  CreateShotWithFilesPathInput,
  CreateShotWithGenerationPathInput,
  CreateShotWithGenerationsPathInput,
} from './shotCreationTypes';
import { applyAtomicShotCacheUpdate } from './shotCacheUpdate';
import { enqueueGenerationsInvalidation } from '@/shared/hooks/invalidation/useGenerationInvalidation';
import { insertAutoPositionedShotGeneration } from '@/shared/hooks/shots/addImageToShotHelpers';

export async function createShotWithGenerationPath(
  input: CreateShotWithGenerationPathInput,
): Promise<ShotCreationResult> {
  const {
    selectedProjectId,
    shotName,
    generationId,
    generationPreview,
    shots,
    queryClient,
    createShotWithImage,
  } = input;

  const rpcResult = await createShotWithImage({
    projectId: selectedProjectId,
    shotName,
    generationId,
  });

  applyAtomicShotCacheUpdate({
    selectedProjectId,
    shotId: rpcResult.shotId,
    shotName: rpcResult.shotName || shotName,
    shotGenerationId: rpcResult.shotGenerationId,
    generationId,
    generationPreview,
    shots,
    queryClient,
  });

  return {
    shotId: rpcResult.shotId,
    shotName: rpcResult.shotName,
    generationIds: [generationId],
  };
}

export async function createShotWithFilesPath(
  input: CreateShotWithFilesPathInput,
): Promise<ShotCreationResult> {
  const {
    selectedProjectId,
    shotName,
    files,
    aspectRatio,
    shots,
    onProgress,
    createShot,
    uploadToShot,
  } = input;

  const created = await createShot({
    name: shotName,
    projectId: selectedProjectId,
    aspectRatio: aspectRatio || undefined,
    shouldSelectAfterCreation: false,
  });

  const newShotId = created?.shot?.id;
  if (!newShotId) {
    throw new Error('Shot creation failed - no ID returned');
  }

  const uploadResult = await uploadToShot({
    imageFiles: files,
    targetShotId: newShotId,
    currentProjectQueryKey: selectedProjectId,
    currentShotCount: shots?.length ?? 0,
    onProgress,
  });

  if (!uploadResult?.shotId) {
    throw new Error('File upload failed - no images processed');
  }

  return {
    shotId: newShotId,
    shotName: created.shot?.name || shotName,
    shot: created.shot,
    generationIds: uploadResult.generationIds,
  };
}

export async function createShotWithGenerationsPath(
  input: CreateShotWithGenerationsPathInput,
): Promise<ShotCreationResult> {
  const {
    selectedProjectId,
    shotName,
    generationIds,
    queryClient,
    createShot,
  } = input;

  const createResult = await createShot({
    name: shotName,
    projectId: selectedProjectId,
    shouldSelectAfterCreation: false,
  });

  if (!createResult?.shot?.id) {
    throw new Error('Shot creation failed - no ID returned');
  }

  const shotId = createResult.shot.id;
  for (const generationId of generationIds) {
    await insertAutoPositionedShotGeneration(shotId, generationId);
  }

  enqueueGenerationsInvalidation(queryClient, shotId, {
    reason: 'create-shot-with-generations',
    scope: 'all',
    includeShots: true,
    projectId: selectedProjectId,
    includeProjectUnified: true,
  });

  return {
    shotId,
    shotName: createResult.shot.name || shotName,
    shot: createResult.shot,
    generationIds,
  };
}

export async function createEmptyShotPath(
  input: CreateEmptyShotPathInput,
): Promise<ShotCreationResult> {
  const { selectedProjectId, shotName, aspectRatio, createShot } = input;

  const createResult = await createShot({
    name: shotName,
    projectId: selectedProjectId,
    aspectRatio: aspectRatio || undefined,
    shouldSelectAfterCreation: false,
  });

  if (!createResult?.shot?.id) {
    throw new Error('Shot creation failed - no ID returned');
  }

  return {
    shotId: createResult.shot.id,
    shotName: createResult.shot.name || shotName,
    shot: createResult.shot,
  };
}

import type { QueryClient } from '@tanstack/react-query';
import { getSupabaseClient as supabase } from '@/integrations/supabase/client';
import type { GenerationRow } from '@/domains/generation/types';
import { queryKeys } from '@/shared/lib/queryKeys';
import { isNotFoundError } from '@/shared/constants/supabaseErrors';
import {
  calculateNextAvailableFrame,
  ensureUniqueFrame,
} from '@/shared/lib/timelinePositionCalculator';
import { updateAllShotsCaches } from './cacheUtils';
import { isQuotaOrServerError } from './shotMutationHelpers';

export interface AddImageToShotVariables {
  shot_id: string;
  generation_id: string;
  project_id: string;
  imageUrl?: string;
  thumbUrl?: string;
  timelineFrame?: number | null;
  skipOptimistic?: boolean;
}

interface CanonicalShotGenerationIdentity {
  generationId: string;
  shotEntryId: string;
}

function withLegacyShotGenerationIdentity<T extends Record<string, unknown>>(
  base: T,
  identity: CanonicalShotGenerationIdentity,
) {
  return {
    ...base,
    id: identity.shotEntryId,
    generation_id: identity.generationId,
    shotImageEntryId: identity.shotEntryId,
    shot_generation_id: identity.shotEntryId,
  };
}

export const withVariableMetadata = (data: Record<string, unknown>, variables: AddImageToShotVariables) => ({
  ...data,
  project_id: variables.project_id,
  imageUrl: variables.imageUrl,
  thumbUrl: variables.thumbUrl,
});

async function insertUnpositionedShotGeneration(
  shotId: string,
  generationId: string,
): Promise<Record<string, unknown>> {
  const { data, error } = await supabase().from('shot_generations')
    .insert({
      shot_id: shotId,
      generation_id: generationId,
      timeline_frame: null,
    })
    .select()
    .single();

  if (error) {
    throw error;
  }

  return data as Record<string, unknown>;
}

export async function insertAutoPositionedShotGeneration(
  shotId: string,
  generationId: string,
): Promise<Record<string, unknown>> {
  const { data: rpcResult, error: rpcError } = await supabase().rpc('add_generation_to_shot', {
    p_shot_id: shotId,
    p_generation_id: generationId,
    p_with_position: true,
  });

  if (rpcError) {
    throw rpcError;
  }

  const result = Array.isArray(rpcResult) ? rpcResult[0] : rpcResult;
  return (result || {}) as Record<string, unknown>;
}

async function fetchResolvedTimelineFrame(shotId: string, requestedFrame: number): Promise<number> {
  const { data: existingGens, error: fetchError } = await supabase().from('shot_generations')
    .select('timeline_frame')
    .eq('shot_id', shotId)
    .not('timeline_frame', 'is', null);

  if (fetchError && !isNotFoundError(fetchError)) {
    // Non-critical fetch failure: fall through with empty frame list.
  }

  const existingFrames = (existingGens || [])
    .map((generation) => generation.timeline_frame)
    .filter((frame): frame is number => frame != null && frame !== -1);

  return ensureUniqueFrame(requestedFrame, existingFrames);
}

async function insertExplicitlyPositionedShotGeneration(
  shotId: string,
  generationId: string,
  timelineFrame: number,
): Promise<Record<string, unknown>> {
  const resolvedFrame = await fetchResolvedTimelineFrame(shotId, timelineFrame);
  const { data, error } = await supabase().from('shot_generations')
    .insert({
      shot_id: shotId,
      generation_id: generationId,
      timeline_frame: resolvedFrame,
    })
    .select()
    .single();

  if (error) {
    throw error;
  }

  return data as Record<string, unknown>;
}

export function runAddImageMutation(variables: AddImageToShotVariables): Promise<Record<string, unknown>> {
  const { shot_id, generation_id, timelineFrame } = variables;

  if (timelineFrame === null) {
    return insertUnpositionedShotGeneration(shot_id, generation_id);
  }
  if (timelineFrame === undefined) {
    return insertAutoPositionedShotGeneration(shot_id, generation_id);
  }
  return insertExplicitlyPositionedShotGeneration(shot_id, generation_id, timelineFrame);
}

function resolveOptimisticFrame(
  timelineFrame: AddImageToShotVariables['timelineFrame'],
  currentImages: Array<{ timeline_frame?: number | null }>,
): number | null {
  const existingFrames = currentImages
    .filter((image) => image.timeline_frame != null && image.timeline_frame !== -1)
    .map((image) => image.timeline_frame as number);

  if (timelineFrame === null) {
    return null;
  }
  if (timelineFrame !== undefined) {
    return ensureUniqueFrame(timelineFrame, existingFrames);
  }
  return calculateNextAvailableFrame(existingFrames);
}

function createOptimisticGenerationItem(input: {
  tempId: string;
  shotId: string;
  generationId: string;
  imageUrl?: string;
  thumbUrl?: string;
  timelineFrame: AddImageToShotVariables['timelineFrame'];
  currentImages: Array<{ timeline_frame?: number | null }>;
}) {
  const { tempId, shotId, generationId, imageUrl, thumbUrl, timelineFrame, currentImages } = input;
  const resolvedFrame = resolveOptimisticFrame(timelineFrame, currentImages);
  const identity: CanonicalShotGenerationIdentity = {
    generationId,
    shotEntryId: tempId,
  };

  return withLegacyShotGenerationIdentity({
    location: imageUrl,
    thumbnail_url: thumbUrl || imageUrl,
    imageUrl,
    thumbUrl: thumbUrl || imageUrl,
    timeline_frame: resolvedFrame,
    type: 'image',
    created_at: new Date().toISOString(),
    starred: false,
    name: null,
    based_on: null,
    params: {},
    shot_data: resolvedFrame !== null ? { [shotId]: [resolvedFrame] } : {},
    _optimistic: true,
  }, identity);
}

